const input     = $input.first().json;
const startDate = input.start_date;
const endDate   = input.end_date;
const kwRaw     = input.keywords;

if (!startDate || !endDate) throw new Error('start_date and end_date are required.');
if (!kwRaw || !kwRaw.trim()) throw new Error('keywords field is empty.');

// Parse comma-separated keywords
const keywords = kwRaw.split(',').map(k => k.trim()).filter(k => k.length > 0);
if (keywords.length === 0) throw new Error('No valid keywords after parsing.');

// Generate date range (inclusive)
const dates = [];
const cur = new Date(startDate + 'T00:00:00Z');
const end = new Date(endDate   + 'T00:00:00Z');
if (cur > end) throw new Error('start_date must be on or before end_date.');
while (cur <= end) {
  const y = cur.getUTCFullYear();
  const m = String(cur.getUTCMonth() + 1).padStart(2, '0');
  const d = String(cur.getUTCDate()).padStart(2, '0');
  dates.push(y + '-' + m + '-' + d);
  cur.setUTCDate(cur.getUTCDate() + 1);
}

// Cartesian product: each date x each keyword
const items = [];
for (const date of dates) {
  for (const keyword of keywords) {
    items.push({ json: { date, keyword } });
  }
}
console.log('Work items: ' + items.length + ' (' + dates.length + ' dates x ' + keywords.length + ' keywords)');
return items;

const item         = $input.first().json;
const keyword      = item.keyword;
const targetDate   = item.date;
const CM_API_KEY   = "mr3oBmqcPm9jR687ZUljv2Iz062gkkH65AX9zhWW";

const CM_ENDPOINT = 'https://media-api-trial.onclusive.com/v1/search/articles';
const LIMIT       = 100;
const MAX_PAGES   = 100;

const EXCLUDED_DOMAINS = [
  'msn.com', 'patch.com', 'tezzbuzz.com', 'vrmintel.com',
  'onlinelibrary.wiley.com', 'cryptopanic.com', 'pubmed.ncbi.nlm.nih.gov',
  'dailymed.nlm.nih.gov', 'newsnowchicago.com', 'tandfonline.com',
  'exbulletin.com', 'kerrfatou.com', 'tncontentexchange.com',
  'tallasseetribune.com', 'dailyworldfeed.com', 'timebusinessnews.com',
  'limitedliability.solutions', 'e-stardom.com', 'byteseu.com'
];

let page = 1, total = Infinity, fetched = 0;
const allArticles = [];

while (page <= MAX_PAGES && (page - 1) * LIMIT < total) {
  const body = {
    query: { simple: {
      terms: '"' + keyword + '"',
      case_sensitive_terms: '', operator: 'and',
      search_fields: ['title', 'content']
    }},
    limit: LIMIT, page,
    filters: {
      date: { start: targetDate + ' 00:00', end: targetDate + ' 23:59', time_zone: '-04:00' },
      lang: [], publication: [],
      pagerank: { min: 0, max: 10 }, country: ['USA'], relevance: { min: 0 },
      article_sentiment: { positive: true, neutral: true, negative: true },
      es_filter: {}
    },
    exclude: { country: [], domains: EXCLUDED_DOMAINS },
    sort: ['published_on'], remove_duplicates: true, profile_uuid: null,
    return_fields: ['published_on', 'title', 'summary', 'url'],
    media_types: ['web']
  };

  const res = await fetch(CM_ENDPOINT, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-API-Key': CM_API_KEY },
    body: JSON.stringify(body)
  });
  if (!res.ok) throw new Error(
    'CM error | kw: ' + keyword + ' | date: ' + targetDate + ' | page: ' + page + ' | status: ' + res.status
  );

  const data = await res.json();
  if (page === 1) { total = data.total || 0; if (total === 0) break; }

  const articles = data.articles || data.data || data.results || [];
  for (const a of articles) {
    allArticles.push({
      keyword, pull_date: targetDate,
      title:        a.title        || null,
      summary:      a.summary      || null,
      url:          a.url          || null,
      published_on: a.published_on || null
    });
  }
  fetched += articles.length;
  if (articles.length < LIMIT) break;
  page++;
}

return [{ json: {
  keyword,
  pull_date:        targetDate,
  articles:         allArticles,
  total_available:  total === Infinity ? 0 : total,
  pages_run:        page - 1,
  articles_fetched: fetched
}}];
